            Tags = """["vendors","reference","procurement"]""",
            ContentJson = """{"title":"Vendors Field Reference","groups":[{"heading":"Vendor Form Fields — Contact Section","items":[{"label":"Company Name (required)","value":"The vendor's legal or trade name. Required. This is how the vendor appears in lists, menus, and on purchase orders."},{"label":"Contact Name","value":"Optional. The main person you deal with at the vendor. Shown under the company name on the vendor's details."},{"label":"Email","value":"Optional. The vendor's main email address. If you enter one, it must be a valid email."},{"label":"Phone","value":"Optional. The vendor's main phone number."},{"label":"Notes","value":"Optional. Free-form notes about the vendor — special instructions, account numbers, or anything worth remembering."}]},{"heading":"Vendor Form Fields — Address Section (sidebar)","items":[{"label":"Address Line 1","value":"Optional. The vendor's street address."},{"label":"City","value":"Optional. City name."},{"label":"State","value":"Optional. Pick the state from the menu."},{"label":"ZIP Code","value":"Optional. A 5-digit or 9-digit ZIP code."},{"label":"Country","value":"Optional. Country name or code. Defaults to US."}]},{"heading":"Vendor Form Fields — Settings Section (sidebar)","items":[{"label":"Payment Terms","value":"Pick from Due on Receipt, Net 15, Net 30, Net 45, Net 60, or COD (or leave it blank). This becomes the default terms on purchase orders you place with this vendor."},{"label":"Active (on/off, edit only)","value":"An on/off switch that controls whether the vendor shows up in active vendor lists and when picking a vendor for a purchase order. It only appears when editing an existing vendor — new vendors start out active."}]},{"heading":"Table Columns","items":[{"label":"Company Name","value":"Sortable. The vendor's company name, shown in bold."},{"label":"Contact","value":"Sortable. The main contact's name. Shows a dash when empty."},{"label":"Email","value":"Sortable. The contact email. Shows a dash when empty."},{"label":"Phone","value":"Sortable. The contact phone number. Shows a dash when empty."},{"label":"Active","value":"Sortable and filterable. A green 'Active' or gray 'Inactive' label."},{"label":"POs","value":"Sortable. How many purchase orders are tied to this vendor."},{"label":"Created","value":"Sortable. The date the vendor was added."}]},{"heading":"Vendor Details — Info Tab","items":[{"label":"Status","value":"Shows whether the vendor is Active (green) or Inactive (gray)."},{"label":"Email","value":"The vendor's email address, when there is one."},{"label":"Phone","value":"The vendor's phone number, when there is one."},{"label":"Payment Terms","value":"The vendor's agreed payment terms, when set."},{"label":"Address","value":"The vendor's address, shown when any address field is filled in."},{"label":"Notes","value":"Free-form notes about the vendor, when there are any."},{"label":"Accounting reference","value":"Shows only when your accounting system (such as QuickBooks) owns this vendor. It's the same vendor over in the books, so AP and purchasing are looking at one supplier, not two."},{"label":"Created / Updated","value":"When the vendor was added and last changed."},{"label":"Activity Log","value":"A running history of every change made to the vendor — useful when a buyer needs to see who changed a term or a contact, and when."}]},{"heading":"Vendor Details — Purchase Orders Tab","items":[{"label":"PO Number","value":"The purchase order number. Click it to open that order."},{"label":"Status","value":"A colored label showing where the order stands (such as Draft, Submitted, Acknowledged, Partially Received, Received, Closed, or Cancelled)."},{"label":"Expected Delivery Date","value":"When the order is expected to arrive."},{"label":"Created","value":"When the order was created."},{"label":"Empty state","value":"When the vendor has no purchase orders, you'll see 'No purchase orders'."}]},{"heading":"Vendor Details — Scorecard Tab","items":[{"label":"Overall Grade","value":"A letter grade from A to F, shown as a colored label — green for A, down to red for F."},{"label":"Overall Score","value":"A score out of 100, shown next to the grade."},{"label":"Evaluation Period","value":"The date range the scorecard covers."},{"label":"On-Time Delivery (40% of the score)","value":"The share of deliveries that arrived on or before the expected date, plus supporting figures like total orders, lines received, and how many arrived late."},{"label":"Quality Acceptance (30% of the score)","value":"How much of what the vendor shipped was accepted, plus supporting figures like how many items were inspected, rejected, and flagged for a quality issue."},{"label":"Price (20% of the score)","value":"Supporting figures for cost: total spend and the average difference between the price you paid and the expected price."},{"label":"Quantity Accuracy (10% of the score)","value":"How closely the vendor ships the quantities you ordered."},{"label":"Total Spend","value":"The total dollars spent with this vendor over the period."}]},{"heading":"Buttons and Actions","items":[{"label":"New Vendor","value":"Starts adding a vendor. It's in the page header."},{"label":"Save / Create Vendor","value":"Saves a new vendor or your changes to an existing one. It stays grayed out until the form is filled in correctly; hover over it to see what still needs attention."},{"label":"Cancel","value":"Closes without saving. If you have unsaved changes, you'll be asked to confirm first."},{"label":"Edit","value":"The pencil button at the top of the vendor's details. Opens the vendor for editing with its current information filled in."},{"label":"Close","value":"The X button at the top of the vendor's details. Closes it and returns you to the vendor list."},{"label":"Activate / Deactivate","value":"At the bottom of the Info tab. Switches the vendor between Active and Inactive. Inactive vendors are kept but hidden from active lists."},{"label":"Delete","value":"At the bottom of the Info tab. Removes the vendor from view. The record is kept behind the scenes, not erased."},{"label":"Row click","value":"Clicking any row in the vendor list opens that vendor's details, with Info, Purchase Orders, and Scorecard tabs."}]},{"heading":"Validation Rules","items":[{"label":"Company Name","value":"Required. It can't be empty. It's the only field you must fill in."},{"label":"Email","value":"Optional, but if you enter one it has to be a valid email (like user@domain.com)."},{"label":"All other fields","value":"Optional, with no special length or format rules."},{"label":"Save button hint","value":"When the form isn't ready to save, hover over the Save button to see which fields still need attention."}]},{"heading":"When Accounting Is Connected","items":[{"label":"Standalone (no accounting system)","value":"You run the vendor list here — add, edit, retire, and reactivate vendors, and every field is yours to change."},{"label":"Connected (accounting system linked)","value":"Your accounting system owns the vendor list, so vendors are view-only here — make edits over there and they show up on your side. You still get the full vendor list, order history, and scorecard to buy against."},{"label":"Accounting reference","value":"Appears on vendors that come from your accounting system. It links this supplier to the same one in the books, so a buyer and the AP clerk are never arguing over two versions of one vendor."},{"label":"Which system it came from","value":"Tells you a vendor came in from your accounting system (such as QuickBooks), so you know to make changes there rather than here."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
